class Solution {
public:
    vector<vector<int>> validArrangement(vector<vector<int>>& pairs) {
        unordered_map<int, int> mp;
        for (auto& p : pairs) {
            mp[p[0]] = p[1];
        }
        vector<vector<int>> res;
        int cur = pairs[0][0];
        while (mp.size()) {
            res.push_back({cur, mp[cur]});
            if (--mp[cur] == 0) {
                mp.erase(cur);
            }
            cur = mp[cur];
        }
        return res;
    }
};
